// ti (tigrinya), so (somali) et zh (chinois).

function m(en, es, pt, ar, ru, uk, tr, fa, sq, ti, so, zh) {
  return { en, es, pt, ar, ru, uk, tr, fa, sq, ti, so, zh }
}

